import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const _=JSON.parse('{"title":"出使锡耶纳","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/51-出使锡耶纳.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/51-出使锡耶纳.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/51-出使锡耶纳.md"};function o(n,a,s,m,p,d){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使锡耶纳",tabindex:"-1"},[t("出使锡耶纳 "),e("a",{class:"header-anchor",href:"#出使锡耶纳","aria-label":'Permalink to "出使锡耶纳"'},"​")],-1),e("p",null,"出使锡耶纳 信件2",-1),e("p",null,"诸位大人钧鉴： 在前天到达锡耶纳后，我立即向诸位大人去信，报告了我听说的关于 特使的一切事情，以及他们如何决定在这里向他致敬。我希望我的信件安 全抵达了你们那里，所以就不重复其中的内容了。就像我向诸位大人提到 过的，特使昨晚在帕利亚歇脚。但我没有赶去那里，而是到了圣奎里科， 因为我觉得最好是在特使的随从们晚上到达时见见他们，而不是在他们早 上启程时见。我是在圣奎里科过的夜，因为无论枢机主教的随从们是按原 计划前往布翁孔文托，还是在这里驻留，他们都得经过圣奎里科。但枢机 主教改变了计划，决定亲自带领一部分随员从帕利亚前往皮恩扎——他会 在那里受到皮科洛米尼的款待。其余的随从则被他派去了圣奎里科。由于 我想知道特使身边骑士的准确数目，所以，在看到抵达这里的那批人后， 我便在拂晓派信使前去皮恩扎，以清点特使身边的骑士数目，而我自己则 留在圣奎里科清点其余的人数。信使后来返回汇报说，在枢机主教及其随 从到达后，他自己又在那里待了10小时， 一共见到了39骑。圣奎里科这 里共来了57骑，另有大约10人奔向锡耶纳去了。统而计之的话，大约有 110名骑士随行。我在圣奎里科一直待到22点，以确定所有的人都到了。 除非另有从罗马前来的人，特使身边的人数不会超过上面所说的110。他 的随从和管家说他带了150人，但这只是因为他们觉得人数多就有面子。 除了上面提到的马匹数目外，我还数到了32只驮运用的骡子，但枢机主教 手下的人说有40只。不过，正如我所说，这些东西的数目并没有那么多。 特使还带了50名马夫和仆人，而据他的信使说，他们大多像是刚从斯廷凯 监狱⑨放出来的。对于主教大人的内务状况，这些就是我所能打听到的全",-1),e("p",null,"①佛罗伦萨的监狱俗称“斯廷凯” ( Stinche), 这是托斯卡纳格雷韦谷地一座城堡的名字，那里的居民 发动反叛，佛罗伦萨人用一圈木栅栏将此城堡包围起来，从而改为一个监狱将居民都关押起来。此后，佛 罗伦萨的新监狱也循例使用此名。 ——英译本注",-1),e("p",null,"马基雅维利全集 Opere complete di Niccolò Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{_ as __pageData,f as default};
